const ADMIN_SECTION_LOADERS={suggestions:()=>loadSuggestionsSectionData(),locations:()=>loadLocations(),dashboard:()=>loadDashboard(),engagement:()=>loadEngagement(),dilemmas:()=>loadDilemmas(),calibration:()=>loadCalibration(),trace:()=>setupTrace(),"calibration-verify":()=>loadCalibrationVerify(),announcements:()=>loadAnnouncements(),"llm-resources":()=>loadLLMResources(),"display-manager":()=>loadDisplayManager(),"cvl-proposal":()=>loadCvlProposal(),"cvl-official-info":()=>loadCvlOfficialInfo(),bus:()=>loadBusSettings(),"music-poll":()=>loadMusicPollAdmin(),nfc:()=>loadNfcAdmin(),backup:()=>loadBackup(),development:()=>loadDevelopment(),};function applySuggestionsSubtab(tab){const t=["list","stream","archive"].includes(tab)?tab:"list";document.querySelectorAll("#section-suggestions .logs-tab").forEach((btn)=>{const isActive=btn.dataset.logsTab===t;btn.classList.toggle("active",isActive);btn.setAttribute("aria-selected",isActive?"true":"false");});document.getElementById("sug-panel-list")?.classList.toggle("hidden",t!=="list");document.getElementById("logs-panel-stream")?.classList.toggle("hidden",t!=="stream");document.getElementById("logs-panel-archive")?.classList.toggle("hidden",t!=="archive");}
