const ADMIN_PALETTE_ENTRIES=[{section:"dashboard",label:"Tableau de bord",hint:"Stats, graphiques, contrôles",kw:"accueil"},{section:"engagement",label:"Engagement",hint:"Cartes spéciales, humeur, devinettes",kw:"stats"},{section:"suggestions",label:"Suggestions",hint:"Liste, logs d’activité, archive",kw:"idées votes historique debug"},{section:"dilemmas",label:"Dilemmes",hint:"Question swipe du jour",kw:"swipe"},{section:"cvl-proposal",label:"Proposition officielle CVL",hint:"Texte affiché aux élèves",kw:"cvl"},{section:"cvl-official-info",label:"Informations officielles CVL",hint:"Bandeaux info",kw:"cvl"},{section:"announcements",label:"Annonces",hint:"Messages display",kw:"bandeau"},{section:"locations",label:"Lieux",hint:"Salles et emplacements",kw:"salles"},{section:"calibration",label:"Calibration IA",hint:"Exemples d’entraînement",kw:"prompt"},{section:"trace",label:"Traçabilité IA",hint:"Traces de traitement",kw:"llm"},{section:"calibration-verify",label:"Vérification calibration",hint:"Contrôle des corrections",kw:"validation"},{section:"llm-resources",label:"Ressources IA",hint:"Modèles, limites",kw:"ollama"},{section:"nfc",label:"NFC / Signalements",hint:"Lieux NFC, maintenance terrain",kw:"nfc tag terrain signalement"},{section:"music-poll",label:"Sondage musique",hint:"Sonnerie, Spotify",kw:"audio"},{section:"display-manager",label:"Affichage dynamique",hint:"Pages /tv",kw:"tv écran"},{section:"bus",label:"Horaires bus",hint:"GTFS, lignes",kw:"transport"},{section:"backup",label:"Backup & historique",hint:"Sauvegardes, archive",kw:"export"},{section:"development",label:"Notes & idées",hint:"Bloc-notes admin",kw:"dev"},];let adminPaletteFiltered=[];let adminPaletteSelected=0;function isAdminPaletteInputBlocked(target){if(!target||typeof target.nodeType!=="number")return false;const tag=target.tagName;if(tag==="INPUT"||tag==="TEXTAREA"||tag==="SELECT")return true;if(target.closest?.("[contenteditable]"))return true;if(target.closest?.(".ql-editor"))return true;return false;}
function updateAdminPaletteUi(filter){const listEl=document.getElementById("admin-command-palette-list");if(!listEl)return;const term=(filter||"").trim().toLowerCase();adminPaletteFiltered=ADMIN_PALETTE_ENTRIES.filter((e)=>{if(!term)return true;const hay=`${e.label} ${e.hint || ""} ${e.kw || ""}`.toLowerCase();return hay.includes(term);});if(!adminPaletteFiltered.length){adminPaletteSelected=0;listEl.innerHTML='<li class="admin-command-palette-empty"><span class="empty-msg">Aucune section ne correspond.</span></li>';return;}
if(adminPaletteSelected>=adminPaletteFiltered.length){adminPaletteSelected=Math.max(0,adminPaletteFiltered.length-1);}
listEl.innerHTML=adminPaletteFiltered.map((e,i)=>`
        <li>
            <button type="button" role="option" class="admin-command-palette-item${i === adminPaletteSelected ? " is-active" : ""}" data-idx="${i}">
                <span class="admin-command-palette-item__label">${esc(e.label)}</span>
                <span class="admin-command-palette-item__hint">${esc(e.hint || "")}</span>
            </button>
        </li>`).join("");listEl.querySelectorAll(".admin-command-palette-item").forEach((btn)=>{btn.addEventListener("click",()=>applyAdminPaletteChoice(parseInt(btn.dataset.idx,10)));});}
function applyAdminPaletteChoice(idx){const e=adminPaletteFiltered[idx];if(!e)return;closeAdminCommandPalette();activateAdminSection(e.section);}
function openAdminCommandPalette(){const modal=document.getElementById("admin-command-palette");if(!modal)return;modal.classList.remove("hidden");adminPaletteSelected=0;const input=document.getElementById("admin-command-palette-input");if(input){input.value="";updateAdminPaletteUi("");setTimeout(()=>input.focus(),10);}}
function closeAdminCommandPalette(){document.getElementById("admin-command-palette")?.classList.add("hidden");}
function setupAdminCommandPalette(){const modal=document.getElementById("admin-command-palette");const input=document.getElementById("admin-command-palette-input");const backdrop=document.getElementById("admin-command-palette-backdrop");document.getElementById("admin-jump-open")?.addEventListener("click",openAdminCommandPalette);backdrop?.addEventListener("click",closeAdminCommandPalette);input?.addEventListener("input",()=>{adminPaletteSelected=0;updateAdminPaletteUi(input.value);});input?.addEventListener("keydown",(e)=>{if(e.key==="ArrowDown"){if(!adminPaletteFiltered.length)return;e.preventDefault();adminPaletteSelected=Math.min(adminPaletteSelected+1,adminPaletteFiltered.length-1);updateAdminPaletteUi(input.value);return;}
if(e.key==="ArrowUp"){if(!adminPaletteFiltered.length)return;e.preventDefault();adminPaletteSelected=Math.max(adminPaletteSelected-1,0);updateAdminPaletteUi(input.value);return;}
if(e.key==="Enter"){if(!adminPaletteFiltered.length)return;e.preventDefault();applyAdminPaletteChoice(adminPaletteSelected);}});}
function setupAdminShortcutsHelp(){const modal=document.getElementById("admin-shortcuts-modal");const close=()=>modal?.classList.add("hidden");document.getElementById("admin-shortcuts-help")?.addEventListener("click",()=>modal?.classList.remove("hidden"));document.getElementById("admin-shortcuts-modal-close")?.addEventListener("click",close);document.getElementById("admin-shortcuts-modal-backdrop")?.addEventListener("click",close);}
