function renderStatusChart(d){const cv=document.getElementById("chart-statuses");const l=Object.keys(d).filter((k)=>d[k]>0);if(chartStatuses)chartStatuses.destroy();chartStatuses=new Chart(cv,{type:"bar",data:{labels:l,datasets:[{data:l.map((k)=>d[k]),backgroundColor:l.map((k)=>STATUS_COLORS[k]||"#94a3b8"),borderWidth:0,borderRadius:6}]},options:{responsive:true,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true,ticks:{stepSize:1}}}}});}
