let logsLastId=0;let logsPollInterval=null;const LOG_EVENT_LABELS={suggestion_submitted:"Soumis",suggestion_accepted:"Validé",suggestion_rejected:"Refus (traitement)",filter_blocked:"Refus (filtre)",argument_rejected:"Arg. refusé",status_changed:"Statut",troll_blocked:"Anti-troll",announcement_created:"Annonce IA",proposal_argument_submitted:"Débat CVL",proposal_argument_accepted:"Débat accepté",proposal_argument_rejected:"Débat refusé",suggestion_argument_accepted:"Arg. accepté",suggestion_deleted:"Supprimé",backup_restored:"Backup",};const LOG_EVENT_COLORS={suggestion_submitted:"#3b82f6",suggestion_accepted:"#22c55e",suggestion_rejected:"#ef4444",filter_blocked:"#ea580c",argument_rejected:"#dc2626",status_changed:"#8b5cf6",troll_blocked:"#991b1b",announcement_created:"#06b6d4",proposal_argument_submitted:"#0d9488",proposal_argument_accepted:"#059669",proposal_argument_rejected:"#be123c",suggestion_argument_accepted:"#16a34a",suggestion_deleted:"#64748b",backup_restored:"#475569",};const LOG_REFUSAL_TYPES=new Set(["suggestion_rejected","filter_blocked","argument_rejected","proposal_argument_rejected","troll_blocked",]);function parseLogDetailJson(detailStr){if(!detailStr||typeof detailStr!=="string")return null;const t=detailStr.trim();if(!t.startsWith("{"))return null;try{return JSON.parse(t);}catch(e){return null;}}
function logEntryHtml(l){const label=LOG_EVENT_LABELS[l.event_type]||l.event_type;const color=LOG_EVENT_COLORS[l.event_type]||"#94a3b8";const timeFull=l.created_at?new Date(l.created_at).toLocaleString("fr-FR",{dateStyle:"short",timeStyle:"medium"}):"";const refusal=LOG_REFUSAL_TYPES.has(l.event_type);const rowClass=refusal?"log-item log-item--refusal":"log-item";const detailStr=l.detail&&String(l.detail).trim();const detailJson=parseLogDetailJson(detailStr);let detailHtml="";if(detailStr){const detailTitle=refusal?"Motif, extrait ou texte concerné":"Détail";let bodyInner=esc(l.detail);if(detailJson&&(detailJson.title||detailJson.new_status)){bodyInner=[detailJson.new_status?`<div class="log-detail-line"><strong>Statut</strong> · ${esc(detailJson.new_status)}</div>`:"",detailJson.title?`<div class="log-detail-line log-detail-line--title">${esc(detailJson.title)}</div>`:"",].filter(Boolean).join("");}else{bodyInner=`<div class="log-detail-body">${esc(l.detail)}</div>`;}
detailHtml=`<div class="log-detail-block"><span class="log-detail-title">${detailTitle}</span>${bodyInner}</div>`;}
let actionHtml="";if(detailJson&&detailJson.suggestion_id){actionHtml=`<div class="log-detail-actions"><button type="button" class="btn btn-sm btn-secondary log-open-suggestion-btn" data-sid="${detailJson.suggestion_id}">Fiche suggestion #${detailJson.suggestion_id}</button></div>`;}
const metaBits=[];if(l.ip)metaBits.push(`IP : ${esc(l.ip)}`);if(l.visitor_id)metaBits.push(`Visiteur : ${esc(l.visitor_id)}`);const metaHtml=metaBits.length?`<div class="log-meta">${metaBits.join(" · ")}</div>`:"";return`<div class="${rowClass}" data-id="${l.id}"><div class="log-head"><span class="log-badge" style="background:${color}">${esc(label)}</span><time class="log-datetime" datetime="${l.created_at || ""}">${timeFull}</time></div><div class="log-msg">${esc(l.message)}</div>${detailHtml}${actionHtml}${metaHtml}</div>`;}
async function loadLogs(){const el=document.getElementById("logs-list");if(!el)return;try{const logs=await API.get("/api/admin/activity-logs?limit=150");el.innerHTML=logs.length?logs.map((l)=>logEntryHtml(l)).join(""):'<p class="empty-msg">Aucun log pour le moment</p>';if(logs.length)logsLastId=Math.max(...logs.map((l)=>l.id));if(!logsPollInterval)logsPollInterval=setInterval(pollLogs,3000);}catch(e){el.innerHTML='<p class="empty-msg">Erreur de chargement</p>';}}
async function pollLogs(){const section=document.getElementById("section-suggestions");if(!section||!section.classList.contains("active"))return;const streamPanel=document.getElementById("logs-panel-stream");if(!streamPanel||streamPanel.classList.contains("hidden"))return;try{const logs=await API.get(`/api/admin/activity-logs?since_id=${logsLastId}&limit=50`);if(!logs.length)return;const el=document.getElementById("logs-list");logs.reverse().forEach((l)=>{const div=document.createElement("div");div.innerHTML=logEntryHtml(l).trim();const node=div.firstElementChild;if(!node)return;node.classList.add("log-item-new");el.insertBefore(node,el.firstChild);if(el.querySelector(".empty-msg"))el.querySelector(".empty-msg").remove();});logsLastId=Math.max(...logs.map((l)=>l.id));}catch(e){}}
